import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Router, NavigationEnd } from '@angular/router';
import { AuthService } from './core/services/auth.service';
import { UiService } from './core/services/ui.service';
import { NotificationContainerComponent } from './core/components/notification-container.component';
import { GlobalLoadingComponent } from './core/components/global-loading.component';
import { filter } from 'rxjs';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    NotificationContainerComponent,
    GlobalLoadingComponent
  ],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss']
})
export class AppComponent {
  private authService = inject(AuthService);
  private uiService = inject(UiService);
  private router = inject(Router);
  
  isAuthenticated$ = this.authService.isAuthenticated$;
  currentUser$ = this.authService.currentUser$;
  currentTitle = 'Dashboard';
  today = new Date();
  sidebarOpen = true;

  constructor() {
    this.router.events
      .pipe(filter(event => event instanceof NavigationEnd))
      .subscribe(() => {
        this.updatePageTitle();
      });
  }

  private updatePageTitle(): void {
    const url = this.router.url;
    const titles: { [key: string]: string } = {
      '/dashboard': 'Dashboard de Performance',
      '/campaigns': 'Campanhas Ativas'
    };
    this.currentTitle = titles[url] || 'Dashboard';
  }

  toggleSidebar(): void {
    this.sidebarOpen = !this.sidebarOpen;
  }

  logout(): void {
    this.authService.logout();
    this.uiService.showInfo('Logout realizado', 'Você foi desconectado com sucesso.');
    this.router.navigate(['/auth']);
  }

  isActive(route: string): boolean {
    return this.router.url === route;
  }
}
<div class="app-layout" *ngIf="isAuthenticated$ | async; else noAuth">
  <!-- Sidebar -->
  <aside class="sidebar" [class.open]="sidebarOpen">
    <div class="logo-section">
      <h1 class="logo">
        <span>meta</span>IQ
        <span class="version">v2.0</span>
      </h1>
    </div>

    <nav class="nav-menu">
      <a
        routerLink="/dashboard"
        class="nav-item"
        [class.active]="isActive('/dashboard')"
      >
        <span class="nav-dot"></span>
        <span>Dashboard</span>
      </a>
      <a
        routerLink="/campaigns"
        class="nav-item"
        [class.active]="isActive('/campaigns')"
      >
        <span class="nav-dot"></span>
        <span>Campanhas</span>
      </a>
    </nav>

    <div class="sidebar-footer">
      <div class="account-badge">
        <div class="account-dot"></div>
        <div>
          <div class="account-name">Conta #12847</div>
          <div class="account-status">Conectada · Meta Ads</div>
        </div>
      </div>
    </div>
  </aside>

  <!-- Main Content -->
  <div class="main-wrapper">
    <!-- Header -->
    <header class="app-header">
      <div class="header-content">
        <button class="toggle-sidebar" (click)="toggleSidebar()">☰</button>
        <div class="header-spacer"></div>
        <div class="user-info" *ngIf="currentUser$ | async as user">
          <span class="user-name">{{ user.name }}</span>
        </div>
        <button class="logout-btn" (click)="logout()">
          <span>Sair</span>
        </button>
      </div>
    </header>

    <!-- Main Content Area -->
    <main class="app-main">
      <div class="main-container">
        <router-outlet></router-outlet>
      </div>
    </main>

    <!-- Footer -->
    <footer class="app-footer">
      <p>
        MetaIQ © 2026 · SQLite Local ·
        {{ today | date: 'dd/MM/yyyy' }}
      </p>
    </footer>
  </div>
</div>

<!-- Global Components -->
<app-notification-container></app-notification-container>
<app-global-loading></app-global-loading>

<!-- Not Authenticated -->
<ng-template #noAuth>
  <div class="auth-wrapper">
    <router-outlet></router-outlet>
  </div>
</ng-template>
